import React, { useState } from 'react';
import logo from '../Assets/Car 24 logo.png';
import CarSlider from '../components/CarSlider';
import './ComingSoon.css';

const ComingSoon = () => {
  const [email, setEmail] = useState('');

  const handleNotify = () => {
    if (email) {
      alert(`Thank you! We will notify you at ${email}`);
      setEmail('');
    } else {
      alert('Please enter your email address');
    }
  };

  const carImages = [
    'https://images.unsplash.com/photo-1605559424843-9e4c228bf1c2?w=400&h=300&fit=crop',
    'https://images.unsplash.com/photo-1552519507-da3b142c6e3d?w=400&h=300&fit=crop',
    'https://images.unsplash.com/photo-1583121274602-3e2820c69888?w=400&h=300&fit=crop',
    'https://images.unsplash.com/photo-1617531653332-bd46c24f2068?w=400&h=300&fit=crop',
    'https://images.unsplash.com/photo-1606664515524-ed2f786a0bd6?w=400&h=300&fit=crop',
    'https://images.unsplash.com/photo-1614200187524-dc4b892acf16?w=400&h=300&fit=crop'
  ];

  return (
    <div className="coming-soon-page">
      <div className="coming-soon-container">
        <div className="details-content">
          <div className="logo-wrapper">
            <img src={logo} alt="Car24 Travels - Self Drive" className="logo-image" />
          </div>
          
          <h1 className="coming-soon-title">COMING SOON</h1>
          
          <p className="subtitle">Your premium car rental experience is on the way — no surge, no hidden fees, just pure driving pleasure.</p>
          
          <div className="car-highlights">
            <div className="highlight-item">
              <div className="highlight-icon">⚡</div>
              <div className="highlight-text">
                <p>Electric & Hybrid</p>
                <p>Zero-emission rides</p>
              </div>
            </div>
            <div className="highlight-item">
              <div className="highlight-icon">🔑</div>
              <div className="highlight-text">
                <p>Keyless Pickup</p>
                <p>24/7 self-service</p>
              </div>
            </div>
            <div className="highlight-item">
              <div className="highlight-icon">🛡️</div>
              <div className="highlight-text">
                <p>Fully Insured</p>
                <p>Premium coverage</p>
              </div>
            </div>
            <div className="highlight-item">
              <div className="highlight-icon">🗺️</div>
              <div className="highlight-text">
                <p>Unlimited Mileage</p>
                <p>Explore without limits</p>
              </div>
            </div>
          </div>
          
          <div className="notify-form">
            <input 
              type="email" 
              placeholder="Enter your email for updates"
              value={email}
              onChange={(e) => setEmail(e.target.value)}
              onKeyPress={(e) => e.key === 'Enter' && handleNotify()}
            />
            <button onClick={handleNotify}>Notify Me</button>
          </div>
          
          <div className="powered-by">
            Powered by <strong>Stackenzo</strong>
          </div>
        </div>
      </div>

      <div className="car-scroll-container">
        <CarSlider carImages={carImages} />
      </div>
    </div>
  );
};

export default ComingSoon;
